external_knowledge:
- Top 3 magnetic field measurements refers to the 3 measurements with the highest absolute magnetic field strength; 
- Site B is one of the measurement sites; 
- Magnetometers are a type of device used for measuring magnetic fields.

sql:
SELECT site_name
FROM measurement_sites
WHERE site_id = 1;

SELECT time_stamp
FROM magnetic_measurements
WHERE measurement_id = 1;

SELECT device_id, COUNT(measurement_id) AS total_measurements
FROM magnetic_measurements
GROUP BY device_id;

SELECT site_name
FROM measurement_sites
WHERE altitude = (SELECT MAX(altitude) FROM measurement_sites);

SELECT time_stamp, absolute_field
FROM magnetic_measurements
WHERE site_id = (SELECT site_id FROM measurement_sites WHERE site_name = 'Site A');

WITH FieldStrengthStats AS (
    SELECT AVG(absolute_field) AS avg_field_strength
    FROM magnetic_measurements
),
AlertCountStats AS (
    SELECT COUNT(*) AS total_alerts
    FROM alerts
)
SELECT fs.avg_field_strength, ac.total_alerts
FROM FieldStrengthStats fs, AlertCountStats ac;

SELECT time_stamp, site_id, absolute_field
FROM magnetic_measurements
WHERE absolute_field = (SELECT MAX(absolute_field) FROM magnetic_measurements);

SELECT site_name, altitude
FROM measurement_sites
ORDER BY altitude DESC;
